// // This T-flip-flop toggles its output on the falling edge of the clock when T is low.
module TFlipFlop(  
    input T,  
    input CLK,  
    output reg Q,  
    output Qn  
);  
    assign Qn = ~Q;  

    always @(posedge CLK) begin  
        if (T)  
            Q <= ~Q;  
    end  
endmodule
